const raw = $input.first().json;
const data = raw.body || raw;
let userMessage = '';
let chatId = '';
let firstName = '';
let callbackType = 'text';
let callbackData = null;
let skipAI = false;
let templateText = '';
let templateMarkup = '';
let callbackMessageId = null;

if (data.callback_query) {
  chatId = String(data.callback_query.message.chat.id);
  firstName = data.callback_query.from.first_name || '';
  callbackData = data.callback_query.data;
  callbackMessageId = data.callback_query.message.message_id;

  if (callbackData === 'noop') {
    skipAI = true;
    callbackType = 'noop';
  } else {
    const callbackMap = {
      'confirm_order': 'Да, хочу оформить заказ на эти запчасти',
      'cancel_order': 'Отменить заказ',
      'new_search': 'Хочу найти другую запчасть',
      'add_parts': 'Хочу добавить ещё запчасти к заказу',
      'contact_manager': 'Хочу связаться с менеджером напрямую',
      'finish': 'Спасибо, завершить диалог'
    };
    if (callbackMap[callbackData]) {
      callbackType = callbackData;
      userMessage = callbackMap[callbackData];
    } else {
      callbackType = 'callback';
      userMessage = callbackData;
    }
  }
} else if (data.message) {
  chatId = String(data.message.chat.id);
  firstName = data.message.from.first_name || '';
  userMessage = data.message.text || '/start';
  if (data.message.contact) {
    callbackType = 'contact';
    userMessage = 'Мой номер телефона: ' + data.message.contact.phone_number;
  }
}

var templates = {
  '_start': {
    text: 'Здравствуйте🙋‍��️! Я - консультант АвтоДеталь. Я помогу подобрать запчасти для вашего автомобиля. Укажите марку, модель авто и какая деталь нужна🚗.',
    buttons: [[{text: '\uD83D\uDD0D Найти запчасть', callback_data: 'new_search'}]]
  },
  'new_search': {
    text: 'Какую запчасть ищем? Укажите название детали и марку/модель авто.\nНапример: колодки Toyota Camry 2018',
    buttons: []
  },
  'add_parts': {
    text: 'Какую запчасть добавить к заказу? Укажите название детали (2-3 слова).\nНапример: масляный фильтр Camry',
    buttons: []
  },
  'cancel_order': {
    text: 'Заказ отменён. Если передумаете — я на связи!',
    buttons: [[{text: '\uD83D\uDD0D Найти запчасть', callback_data: 'new_search'}]]
  },
  'finish': {
    text: 'Спасибо за заказ! Менеджер свяжется с вами в ближайшее время. До встречи!',
    buttons: [[{text: '\uD83D\uDD0D Найти запчасть', callback_data: 'new_search'}]]
  },
  'contact_manager': {
    text: 'Свяжитесь с нашим менеджером:\nТелефон: +7 711 463 6644\nМы ответим в рабочее время (09:00-18:00).',
    buttons: [[{text: '\uD83D\uDD0D Найти запчасть', callback_data: 'new_search'}]]
  }
};

var templateKey = '';
if (userMessage === '/start') {
  templateKey = '_start';
} else if (templates[callbackType]) {
  templateKey = callbackType;
}

if (templateKey) {
  skipAI = true;
  var t = templates[templateKey];
  templateText = t.text;
  templateMarkup = JSON.stringify({inline_keyboard: t.buttons});
}

return {
  json: {
    userMessage,
    chatId,
    firstName,
    callbackType,
    callbackData,
    skipAI,
    templateText,
    templateMarkup,
    callbackMessageId
  }
};

const aiResponse = $input.first().json.output;
const prepData = $('Podgotovka vvoda').first().json;
const chatId = prepData.chatId;
const callbackType = prepData.callbackType || 'text';

let text = aiResponse || 'Произошла ошибка. Попробуйте ещё раз.';
text = text.replace(/[\*\`\[\]]/g, '');
text = text.replace(/_/g, ' ');
text = text.replace(/\s{2,}/g, ' ');

let buttons = [];
let isOrder = false;
let clientName = '';
let clientPhone = '';
let orderText = '';
const hasError = text.includes('ошибк') || text.includes('not defined') || text.includes('error');
const hasResults = text.includes('тенге') || text.includes(' тг') || text.includes('Артикул:');
const notFound = !hasResults && (text.includes('не найден') || text.includes('не удалось найти') || text.includes('не нашёл') || text.includes('не нашел') || text.includes('нет в каталоге') || text.includes('отсутствует'));

const textLower = text.toLowerCase();
if (!hasError && (text.includes('ORD-') || (textLower.includes('заказ') && textLower.includes('оформлен') && textLower.includes('менеджер')))) {
  isOrder = true;
  var nm = text.match(/Клиент[:\s]+([^\.,:;\n]+)/i);
  if (nm) clientName = nm[1].trim();
  var ph = text.match(/Телефон[:\s]+([^\.,;\s\n]+)/i);
  if (ph) clientPhone = ph[1].trim();
  var userMsg = prepData.userMessage || '';
  if (!clientPhone) {
    var phoneRx = userMsg.match(/(\+?\d[\d\s\-]{7,})/);
    if (phoneRx) clientPhone = phoneRx[1].replace(/[\s\-]/g, '');
  }
  if (!clientName) {
    var words = userMsg.split(/[,\s]+/);
    for (var w = 0; w < words.length; w++) {
      if (words[w].length > 1 && !/^\+?\d/.test(words[w])) {
        clientName = words[w];
        break;
      }
    }
  }
  if (!clientName) clientName = prepData.firstName || '';
  if (clientName) {
    var nameParts = clientName.split(/\s+/);
    if (nameParts.length >= 2 && nameParts.every(function(p) { return p === nameParts[0]; })) {
      clientName = nameParts[0];
    }
  }
  if (clientName && clientName.length > 1) {
    var escaped = clientName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    var dupRx = new RegExp('(' + escaped + ')(?:\\s+\\1)+', 'gi');
    text = text.replace(dupRx, clientName);
  }
  orderText = text;
  var cutIdx = text.search(/\n?\s*(Хочешь|Хотите|Желаете|Могу|Что-то|Нужна ли|Если нужн|Добавить ещё|Есть вопрос)/i);
  if (cutIdx > 0) {
    orderText = text.substring(0, cutIdx).trim();
  }
  buttons = [
    [{ text: '\u2705 Завершить', callback_data: 'finish' }],
    [{ text: '\uD83D\uDD0D Новый поиск', callback_data: 'new_search' }]
  ];
} else if (callbackType === 'confirm_order') {
  buttons = [
    [{ text: '\u274C Отменить заказ', callback_data: 'cancel_order' }]
  ];
} else if (callbackType === 'finish' || callbackType === 'cancel_order' || callbackType === 'contact_manager') {
  buttons = [
    [{ text: '\uD83D\uDD0D Найти запчасть', callback_data: 'new_search' }]
  ];
} else if (notFound) {
  buttons = [
    [{ text: '\uD83D\uDD0D Другой запрос', callback_data: 'new_search' }],
    [{ text: '\uD83D\uDCDE Связаться с менеджером', callback_data: 'contact_manager' }]
  ];
} else if (text.includes('одтверди') || text.includes('одтвержд') || text.includes('оформить заказ')) {
  buttons = [
    [{ text: '\u2705 Подтвердить заказ', callback_data: 'confirm_order' }],
    [{ text: '\u2795 Добавить запчасти', callback_data: 'add_parts' }]
  ];
} else if (hasResults) {
  buttons = [
    [{ text: '\u2795 Добавить запчасти', callback_data: 'add_parts' }],
    [{ text: '\uD83D\uDD0D Другой поиск', callback_data: 'new_search' }]
  ];
} else if (text.includes('телефон') || text.includes('имя и номер')) {
  buttons = [
    [{ text: '\u274C Отменить заказ', callback_data: 'cancel_order' }]
  ];
} else if (callbackType === 'new_search' || callbackType === 'add_parts') {
  buttons = [];
} else if (text.includes('помогу подобрать') || text.includes('Здравствуйте') || text.includes('Добро пожаловать') || text.includes('Приветствую') || text.includes('чем помочь')) {
  buttons = [
    [{ text: '\uD83D\uDD0D Найти запчасть', callback_data: 'new_search' }]
  ];
} else {
  buttons = [
    [{ text: '\uD83D\uDD0D Найти запчасть', callback_data: 'new_search' }]
  ];
}

return {
  json: {
    chat_id: chatId,
    text: text,
    reply_markup: { inline_keyboard: buttons },
    isOrder: isOrder,
    orderText: orderText,
    clientName: clientName,
    clientPhone: clientPhone
  }
};

